import{_ as a,o as l,c as i,a0 as t}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Kick a Player from the Alliance","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/kick-player.md","filePath":"how-to/kick-player.md"}'),r={name:"how-to/kick-player.md"};function o(n,e,h,c,s,k){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="kick-a-player-from-the-alliance" tabindex="-1">Kick a Player from the Alliance <a class="header-anchor" href="#kick-a-player-from-the-alliance" aria-label="Permalink to &quot;Kick a Player from the Alliance&quot;">​</a></h1><p>Use <strong>Kick</strong> when a player left the alliance but should still exist in the kingdom. This is the safe cleanup path for roster changes.</p><blockquote><p>Screenshot placeholder: player-kick.png</p></blockquote><h2 id="why-kick-is-different-from-delete" tabindex="-1">Why kick is different from delete <a class="header-anchor" href="#why-kick-is-different-from-delete" aria-label="Permalink to &quot;Why kick is different from delete&quot;">​</a></h2><p>Kicking a player:</p><ul><li>removes them from the current alliance roster</li><li>keeps their kingdom identity</li><li>keeps their history</li><li>keeps old results and nickname history</li></ul><p>Deleting is much heavier. If the player only left the alliance, kick them instead.</p><h2 id="kick-from-the-players-page" tabindex="-1">Kick from the Players page <a class="header-anchor" href="#kick-from-the-players-page" aria-label="Permalink to &quot;Kick from the Players page&quot;">​</a></h2><ol><li>Open <strong>Players</strong>.</li><li>Find the player.</li><li>Use the <strong>Kick from alliance</strong> action.</li><li>Confirm the warning.</li></ol><p>The confirmation reminds you that the player&#39;s kingdom identity and history will stay intact.</p><h2 id="what-changes-after-the-kick" tabindex="-1">What changes after the kick <a class="header-anchor" href="#what-changes-after-the-kick" aria-label="Permalink to &quot;What changes after the kick&quot;">​</a></h2><ul><li>The player no longer belongs to the current alliance.</li><li>The current alliance membership ends.</li><li>The membership history records the change as <code>kicked</code>.</li><li>Event and analytics history are still preserved.</li></ul><h2 id="when-kick-will-not-help" tabindex="-1">When kick will not help <a class="header-anchor" href="#when-kick-will-not-help" aria-label="Permalink to &quot;When kick will not help&quot;">​</a></h2><p>Do not use kick when you are trying to:</p><ul><li>remove the player from the kingdom entirely</li><li>fix a wrong role assignment for a user account</li><li>move the player to another alliance right away</li></ul><p>For a move between alliances, use the player edit or profile flow that records a transfer.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../reference/alliance-membership.html">How Alliance Membership Works</a></li><li><a href="./delete-restore-player.html">Delete &amp; Restore a Player</a></li><li><a href="./player-profile.html">Read a Player Profile</a></li></ul>',18)])])}const f=a(r,[["render",o]]);export{d as __pageData,f as default};
